program LIPDecide;

{$mode objfpc}{$H+}

uses
  SysUtils, Math;

const
  PI_CONST = 3.1415926535;

type
  POINTRANGE  = 1..100;
  LICRANGE    = 1..15;
  COMPTYPE    = (LT, EQ, GT);
  CONNECTORS  = (NOTUSED, ORR, ANDD);
  COORDINATE  = array[POINTRANGE] of real;
  CMATRIX     = array[LICRANGE, LICRANGE] of CONNECTORS;
  BMATRIX     = array[LICRANGE, LICRANGE] of boolean;
  VECTOR      = array[LICRANGE] of boolean;

var
  X          : COORDINATE;
  Y          : COORDINATE;
  NUMPOINTS  : integer;
  PARAMETERS : record
    LENGTH1  : real;
    RADIUS1  : real;
    EPSILON  : real;
    AREA1    : real;
    Q_PTS    : integer;
    QUADS    : integer;
    DIST     : real;
    N_PTS    : integer;
    K_PTS    : integer;
    A_PTS    : integer;
    B_PTS    : integer;
    C_PTS    : integer;
    D_PTS    : integer;
    E_PTS    : integer;
    F_PTS    : integer;
    G_PTS    : integer;
    LENGTH2  : real;
    RADIUS2  : real;
    AREA2    : real;
  end;
  LCM     : CMATRIX;
  PUM     : BMATRIX;
  CMV     : VECTOR;
  FUV     : VECTOR;
  LAUNCH  : boolean;

  { JSON parser state }
  JsonStr: AnsiString;
  JsonPos: integer;

{ REALCOMPARE function from reference }
function REALCOMPARE(A, B: real): COMPTYPE;
var
  scale, eps, diff: real;
begin
  scale := Abs(A);
  if Abs(B) > scale then
    scale := Abs(B);
  if scale = 0.0 then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;

  eps := 0.5e-5 * scale;
  diff := A - B;
  if diff > eps then
    REALCOMPARE := GT
  else if diff < -eps then
    REALCOMPARE := LT
  else
    REALCOMPARE := EQ;
end;

{ Simple JSON parser }
procedure SkipWhitespace;
begin
  while (JsonPos <= Length(JsonStr)) and (JsonStr[JsonPos] in [' ', #9, #10, #13]) do
    Inc(JsonPos);
end;

function PeekChar: char;
begin
  SkipWhitespace;
  if JsonPos <= Length(JsonStr) then
    PeekChar := JsonStr[JsonPos]
  else
    PeekChar := #0;
end;

function GetChar: char;
begin
  SkipWhitespace;
  if JsonPos <= Length(JsonStr) then
  begin
    GetChar := JsonStr[JsonPos];
    Inc(JsonPos);
  end
  else
    GetChar := #0;
end;

procedure Expect(c: char);
var
  got: char;
begin
  got := GetChar;
  if got <> c then
    raise Exception.Create('Expected ' + c + ' but got ' + got);
end;

function ParseString: string;
var
  c: char;
begin
  Result := '';
  Expect('"');
  while JsonPos <= Length(JsonStr) do
  begin
    c := JsonStr[JsonPos];
    Inc(JsonPos);
    if c = '"' then
      Exit;
    if c = '\' then
    begin
      if JsonPos <= Length(JsonStr) then
      begin
        c := JsonStr[JsonPos];
        Inc(JsonPos);
      end;
    end;
    Result := Result + c;
  end;
end;

function ParseNumber: real;
var
  startPos: integer;
  numStr: string;
begin
  SkipWhitespace;
  startPos := JsonPos;
  while (JsonPos <= Length(JsonStr)) and (JsonStr[JsonPos] in ['0'..'9', '.', '-', '+', 'e', 'E']) do
    Inc(JsonPos);
  numStr := Copy(JsonStr, startPos, JsonPos - startPos);
  Result := StrToFloat(numStr);
end;

function ParseBool: boolean;
begin
  SkipWhitespace;
  if Copy(JsonStr, JsonPos, 4) = 'true' then
  begin
    Inc(JsonPos, 4);
    Result := true;
  end
  else if Copy(JsonStr, JsonPos, 5) = 'false' then
  begin
    Inc(JsonPos, 5);
    Result := false;
  end
  else
    raise Exception.Create('Expected boolean');
end;

procedure ParseNumberArray(var arr: COORDINATE; var count: integer);
var
  c: char;
begin
  count := 0;
  Expect('[');
  if PeekChar <> ']' then
  begin
    repeat
      Inc(count);
      arr[count] := ParseNumber;
      c := PeekChar;
      if c = ',' then GetChar;
    until c <> ',';
  end;
  Expect(']');
end;

procedure SkipValue; forward;

procedure SkipArray;
var
  c: char;
begin
  Expect('[');
  if PeekChar <> ']' then
  begin
    repeat
      SkipValue;
      c := PeekChar;
      if c = ',' then GetChar;
    until c <> ',';
  end;
  Expect(']');
end;

procedure SkipObject;
var
  c: char;
begin
  Expect('{');
  if PeekChar <> '}' then
  begin
    repeat
      ParseString; { key }
      Expect(':');
      SkipValue;
      c := PeekChar;
      if c = ',' then GetChar;
    until c <> ',';
  end;
  Expect('}');
end;

procedure SkipValue;
var
  c: char;
begin
  c := PeekChar;
  case c of
    '{': SkipObject;
    '[': SkipArray;
    '"': ParseString;
    't', 'f': ParseBool;
    else ParseNumber;
  end;
end;

procedure ParseLcmArray;
var
  i, j: integer;
  c: char;
  s: string;
begin
  Expect('[');
  for i := 1 to 15 do
  begin
    if i > 1 then Expect(',');
    Expect('[');
    for j := 1 to 15 do
    begin
      if j > 1 then Expect(',');
      s := ParseString;
      if s = 'NOTUSED' then
        LCM[i, j] := NOTUSED
      else if s = 'ORR' then
        LCM[i, j] := ORR
      else if s = 'ANDD' then
        LCM[i, j] := ANDD;
    end;
    Expect(']');
  end;
  Expect(']');
end;

procedure ParsePumDiagArray;
var
  i: integer;
  c: char;
begin
  Expect('[');
  for i := 1 to 15 do
  begin
    if i > 1 then Expect(',');
    PUM[i, i] := ParseBool;
  end;
  Expect(']');
end;

procedure ParseParameters;
var
  key: string;
  c: char;
begin
  Expect('{');
  repeat
    key := ParseString;
    Expect(':');
    if key = 'LENGTH1' then PARAMETERS.LENGTH1 := ParseNumber
    else if key = 'RADIUS1' then PARAMETERS.RADIUS1 := ParseNumber
    else if key = 'EPSILON' then PARAMETERS.EPSILON := ParseNumber
    else if key = 'AREA1' then PARAMETERS.AREA1 := ParseNumber
    else if key = 'Q_PTS' then PARAMETERS.Q_PTS := Round(ParseNumber)
    else if key = 'QUADS' then PARAMETERS.QUADS := Round(ParseNumber)
    else if key = 'DIST' then PARAMETERS.DIST := ParseNumber
    else if key = 'N_PTS' then PARAMETERS.N_PTS := Round(ParseNumber)
    else if key = 'K_PTS' then PARAMETERS.K_PTS := Round(ParseNumber)
    else if key = 'A_PTS' then PARAMETERS.A_PTS := Round(ParseNumber)
    else if key = 'B_PTS' then PARAMETERS.B_PTS := Round(ParseNumber)
    else if key = 'C_PTS' then PARAMETERS.C_PTS := Round(ParseNumber)
    else if key = 'D_PTS' then PARAMETERS.D_PTS := Round(ParseNumber)
    else if key = 'E_PTS' then PARAMETERS.E_PTS := Round(ParseNumber)
    else if key = 'F_PTS' then PARAMETERS.F_PTS := Round(ParseNumber)
    else if key = 'G_PTS' then PARAMETERS.G_PTS := Round(ParseNumber)
    else if key = 'LENGTH2' then PARAMETERS.LENGTH2 := ParseNumber
    else if key = 'RADIUS2' then PARAMETERS.RADIUS2 := ParseNumber
    else if key = 'AREA2' then PARAMETERS.AREA2 := ParseNumber
    else SkipValue;
    c := PeekChar;
    if c = ',' then GetChar;
  until c <> ',';
  Expect('}');
end;

procedure ParseInput;
var
  key: string;
  c: char;
  dummy: integer;
begin
  Expect('{');
  repeat
    key := ParseString;
    Expect(':');
    if key = 'numpoints' then NUMPOINTS := Round(ParseNumber)
    else if key = 'x' then ParseNumberArray(X, dummy)
    else if key = 'y' then ParseNumberArray(Y, dummy)
    else if key = 'parameters' then ParseParameters
    else if key = 'lcm' then ParseLcmArray
    else if key = 'pum_diag' then ParsePumDiagArray
    else SkipValue;
    c := PeekChar;
    if c = ',' then GetChar;
  until c <> ',';
  Expect('}');
end;

{ Helper: Distance between two points }
function Distance(x1, y1, x2, y2: real): real;
begin
  Distance := Sqrt(Sqr(x2 - x1) + Sqr(y2 - y1));
end;

{ Helper: Triangle area using cross product formula }
function TriangleArea(x1, y1, x2, y2, x3, y3: real): real;
begin
  TriangleArea := Abs((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) / 2.0);
end;

{ Helper: Get quadrant for a point (1-based: I, II, III, IV) }
function GetQuadrant(px, py: real): integer;
begin
  { Priority: I, II, III, IV }
  { (0,0) -> I, (-1,0) -> II, (0,-1) -> III, (0,1) -> I, (1,0) -> I }
  if (REALCOMPARE(px, 0.0) <> LT) and (REALCOMPARE(py, 0.0) <> LT) then
    GetQuadrant := 1
  else if (REALCOMPARE(px, 0.0) = LT) and (REALCOMPARE(py, 0.0) <> LT) then
    GetQuadrant := 2
  else if (REALCOMPARE(px, 0.0) <> GT) and (REALCOMPARE(py, 0.0) = LT) then
    GetQuadrant := 3
  else
    GetQuadrant := 4;
end;

{ Helper: Calculate angle at vertex (second point) formed by three points }
{ Returns the angle in radians, or -1 if undefined (vertex coincides with endpoint) }
function CalcAngle(x1, y1, x2, y2, x3, y3: real): real;
var
  v1x, v1y, v2x, v2y: real;
  dot, ang: real;
  len1, len2: real;
begin
  { Check if first or last point coincides with vertex }
  if (REALCOMPARE(x1, x2) = EQ) and (REALCOMPARE(y1, y2) = EQ) then
  begin
    CalcAngle := -1.0;
    Exit;
  end;
  if (REALCOMPARE(x3, x2) = EQ) and (REALCOMPARE(y3, y2) = EQ) then
  begin
    CalcAngle := -1.0;
    Exit;
  end;

  { Vectors from vertex to other points }
  v1x := x1 - x2;
  v1y := y1 - y2;
  v2x := x3 - x2;
  v2y := y3 - y2;

  dot := v1x * v2x + v1y * v2y;
  len1 := Sqrt(v1x * v1x + v1y * v1y);
  len2 := Sqrt(v2x * v2x + v2y * v2y);

  { Use arccos of normalized dot product }
  ang := dot / (len1 * len2);
  { Clamp to [-1, 1] to avoid numerical issues }
  if ang > 1.0 then ang := 1.0;
  if ang < -1.0 then ang := -1.0;
  CalcAngle := ArcCos(ang);
end;

{ Helper: Circumradius of triangle, returns very large value if degenerate }
function CircumRadius(x1, y1, x2, y2, x3, y3: real): real;
var
  a, b, c, s, area: real;
begin
  a := Distance(x1, y1, x2, y2);
  b := Distance(x2, y2, x3, y3);
  c := Distance(x3, y3, x1, y1);
  s := (a + b + c) / 2.0;
  area := Sqrt(s * (s - a) * (s - b) * (s - c));
  if REALCOMPARE(area, 0.0) = EQ then
    CircumRadius := 1.0e30
  else
    CircumRadius := (a * b * c) / (4.0 * area);
end;

{ Helper: Check if three points can be contained within or on a circle of given radius }
function CanContainInCircle(x1, y1, x2, y2, x3, y3, radius: real): boolean;
var
  cr: real;
  d1, d2, d3, maxDist: real;
begin
  { If all three points are the same, they can be contained in any circle }
  if (REALCOMPARE(x1, x2) = EQ) and (REALCOMPARE(y1, y2) = EQ) and
     (REALCOMPARE(x2, x3) = EQ) and (REALCOMPARE(y2, y3) = EQ) then
  begin
    CanContainInCircle := true;
    Exit;
  end;

  d1 := Distance(x1, y1, x2, y2);
  d2 := Distance(x2, y2, x3, y3);
  d3 := Distance(x3, y3, x1, y1);

  maxDist := d1;
  if d2 > maxDist then maxDist := d2;
  if d3 > maxDist then maxDist := d3;

  { Check if collinear using area }
  if REALCOMPARE(TriangleArea(x1, y1, x2, y2, x3, y3), 0.0) = EQ then
  begin
    { Collinear: min enclosing circle has radius = maxDist / 2 }
    CanContainInCircle := REALCOMPARE(maxDist / 2.0, radius) <> GT;
    Exit;
  end;

  { Non-collinear: compute circumradius }
  cr := CircumRadius(x1, y1, x2, y2, x3, y3);

  { The minimum enclosing circle is either the circumcircle (if acute/right triangle)
    or a circle with diameter = longest side (if obtuse triangle) }
  if (d1*d1 + d2*d2 < d3*d3) or (d2*d2 + d3*d3 < d1*d1) or (d1*d1 + d3*d3 < d2*d2) then
  begin
    { Obtuse triangle: min enclosing circle has diameter = longest side }
    CanContainInCircle := REALCOMPARE(maxDist / 2.0, radius) <> GT;
  end
  else
  begin
    { Acute or right triangle: min enclosing circle is circumcircle }
    CanContainInCircle := REALCOMPARE(cr, radius) <> GT;
  end;
end;

{ Helper: Distance from point to line defined by two points }
function PointToLineDistance(px, py, x1, y1, x2, y2: real): real;
var
  dx, dy, lineLenSq: real;
begin
  dx := x2 - x1;
  dy := y2 - y1;
  lineLenSq := dx * dx + dy * dy;

  if REALCOMPARE(lineLenSq, 0.0) = EQ then
  begin
    { Line endpoints are the same point }
    PointToLineDistance := Distance(px, py, x1, y1);
    Exit;
  end;

  { Distance from point to infinite line }
  PointToLineDistance := Abs(dy * px - dx * py + x2 * y1 - y2 * x1) / Sqrt(lineLenSq);
end;

{ LIC 1: Two consecutive points more than LENGTH1 apart }
function EvalLIC1: boolean;
var
  i: integer;
  d: real;
begin
  EvalLIC1 := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    d := Distance(X[i], Y[i], X[i+1], Y[i+1]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
    begin
      EvalLIC1 := true;
      Exit;
    end;
  end;
end;

{ LIC 2: Three consecutive points that cannot be contained in circle of RADIUS1 }
function EvalLIC2: boolean;
var
  i: integer;
begin
  EvalLIC2 := false;
  if NUMPOINTS < 3 then Exit;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if not CanContainInCircle(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2], PARAMETERS.RADIUS1) then
    begin
      EvalLIC2 := true;
      Exit;
    end;
  end;
end;

{ LIC 3: Three consecutive points forming angle < (PI - EPSILON) or > (PI + EPSILON) }
function EvalLIC3: boolean;
var
  i: integer;
  ang: real;
begin
  EvalLIC3 := false;
  if NUMPOINTS < 3 then Exit;
  for i := 1 to NUMPOINTS - 2 do
  begin
    ang := CalcAngle(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
    if ang < 0 then Continue; { Undefined angle }
    if (REALCOMPARE(ang, PI_CONST - PARAMETERS.EPSILON) = LT) or
       (REALCOMPARE(ang, PI_CONST + PARAMETERS.EPSILON) = GT) then
    begin
      EvalLIC3 := true;
      Exit;
    end;
  end;
end;

{ LIC 4: Three consecutive points forming triangle with area > AREA1 }
function EvalLIC4: boolean;
var
  i: integer;
  area: real;
begin
  EvalLIC4 := false;
  if NUMPOINTS < 3 then Exit;
  for i := 1 to NUMPOINTS - 2 do
  begin
    area := TriangleArea(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
    begin
      EvalLIC4 := true;
      Exit;
    end;
  end;
end;

{ LIC 5: Q_PTS consecutive points in more than QUADS quadrants }
function EvalLIC5: boolean;
var
  i, j, q: integer;
  quadrants: array[1..4] of boolean;
  count: integer;
begin
  EvalLIC5 := false;
  if NUMPOINTS < PARAMETERS.Q_PTS then Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    for q := 1 to 4 do quadrants[q] := false;
    for j := 0 to PARAMETERS.Q_PTS - 1 do
    begin
      q := GetQuadrant(X[i + j], Y[i + j]);
      quadrants[q] := true;
    end;
    count := 0;
    for q := 1 to 4 do
      if quadrants[q] then Inc(count);
    if count > PARAMETERS.QUADS then
    begin
      EvalLIC5 := true;
      Exit;
    end;
  end;
end;

{ LIC 6: Two consecutive points where X[j] - X[i] < 0 (i = j - 1) }
function EvalLIC6: boolean;
var
  i: integer;
begin
  EvalLIC6 := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(X[i+1] - X[i], 0.0) = LT then
    begin
      EvalLIC6 := true;
      Exit;
    end;
  end;
end;

{ LIC 7: N_PTS consecutive points with at least one > DIST from line joining first and last }
function EvalLIC7: boolean;
var
  i, j: integer;
  d: real;
  found: boolean;
begin
  EvalLIC7 := false;
  if NUMPOINTS < 3 then Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    found := false;
    for j := 1 to PARAMETERS.N_PTS - 2 do
    begin
      { Check if first and last are identical }
      if (REALCOMPARE(X[i], X[i + PARAMETERS.N_PTS - 1]) = EQ) and
         (REALCOMPARE(Y[i], Y[i + PARAMETERS.N_PTS - 1]) = EQ) then
      begin
        { Distance from coincident point to intermediate points }
        d := Distance(X[i], Y[i], X[i + j], Y[i + j]);
      end
      else
      begin
        d := PointToLineDistance(X[i + j], Y[i + j], X[i], Y[i], X[i + PARAMETERS.N_PTS - 1], Y[i + PARAMETERS.N_PTS - 1]);
      end;
      if REALCOMPARE(d, PARAMETERS.DIST) = GT then
      begin
        found := true;
        Break;
      end;
    end;
    if found then
    begin
      EvalLIC7 := true;
      Exit;
    end;
  end;
end;

{ LIC 8: Two points separated by K_PTS intervening points, distance > LENGTH1 }
function EvalLIC8: boolean;
var
  i: integer;
  d: real;
begin
  EvalLIC8 := false;
  if NUMPOINTS < 3 then Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    d := Distance(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
    begin
      EvalLIC8 := true;
      Exit;
    end;
  end;
end;

{ LIC 9: Three points separated by A_PTS and B_PTS, cannot be in circle of RADIUS1 }
function EvalLIC9: boolean;
var
  i, j, k: integer;
begin
  EvalLIC9 := false;
  if NUMPOINTS < 5 then Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    if not CanContainInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS1) then
    begin
      EvalLIC9 := true;
      Exit;
    end;
  end;
end;

{ LIC 10: Three points separated by C_PTS and D_PTS forming angle < PI-EPSILON or > PI+EPSILON }
function EvalLIC10: boolean;
var
  i, j, k: integer;
  ang: real;
begin
  EvalLIC10 := false;
  if NUMPOINTS < 5 then Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
  begin
    j := i + PARAMETERS.C_PTS + 1;
    k := j + PARAMETERS.D_PTS + 1;
    ang := CalcAngle(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if ang < 0 then Continue;
    if (REALCOMPARE(ang, PI_CONST - PARAMETERS.EPSILON) = LT) or
       (REALCOMPARE(ang, PI_CONST + PARAMETERS.EPSILON) = GT) then
    begin
      EvalLIC10 := true;
      Exit;
    end;
  end;
end;

{ LIC 11: Three points separated by E_PTS and F_PTS forming triangle with area > AREA1 }
function EvalLIC11: boolean;
var
  i, j, k: integer;
  area: real;
begin
  EvalLIC11 := false;
  if NUMPOINTS < 5 then Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    area := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
    begin
      EvalLIC11 := true;
      Exit;
    end;
  end;
end;

{ LIC 12: Two points separated by G_PTS where X[j] - X[i] < 0 }
function EvalLIC12: boolean;
var
  i: integer;
begin
  EvalLIC12 := false;
  if NUMPOINTS < 3 then Exit;
  for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
  begin
    if REALCOMPARE(X[i + PARAMETERS.G_PTS + 1] - X[i], 0.0) = LT then
    begin
      EvalLIC12 := true;
      Exit;
    end;
  end;
end;

{ LIC 13: Two points separated by K_PTS: one pair > LENGTH1, another pair < LENGTH2 }
function EvalLIC13: boolean;
var
  i: integer;
  d: real;
  foundGT, foundLT: boolean;
begin
  EvalLIC13 := false;
  if NUMPOINTS < 3 then Exit;
  foundGT := false;
  foundLT := false;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    d := Distance(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
      foundGT := true;
    if REALCOMPARE(d, PARAMETERS.LENGTH2) = LT then
      foundLT := true;
  end;
  EvalLIC13 := foundGT and foundLT;
end;

{ LIC 14: Three points separated by A_PTS and B_PTS: one set cannot be in RADIUS1, another can be in RADIUS2 }
function EvalLIC14: boolean;
var
  i, j, k: integer;
  foundNotIn, foundIn: boolean;
begin
  EvalLIC14 := false;
  if NUMPOINTS < 5 then Exit;
  foundNotIn := false;
  foundIn := false;
  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    if not CanContainInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS1) then
      foundNotIn := true;
    if CanContainInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS2) then
      foundIn := true;
  end;
  EvalLIC14 := foundNotIn and foundIn;
end;

{ LIC 15: Three points separated by E_PTS and F_PTS: one set area > AREA1, another area < AREA2 }
function EvalLIC15: boolean;
var
  i, j, k: integer;
  area: real;
  foundGT, foundLT: boolean;
begin
  EvalLIC15 := false;
  if NUMPOINTS < 5 then Exit;
  foundGT := false;
  foundLT := false;
  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    area := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
      foundGT := true;
    if REALCOMPARE(area, PARAMETERS.AREA2) = LT then
      foundLT := true;
  end;
  EvalLIC15 := foundGT and foundLT;
end;

{ Main DECIDE procedure }
procedure DECIDE;
var
  i, j: integer;
  allTrue: boolean;
begin
  { Evaluate all LICs }
  CMV[1] := EvalLIC1;
  CMV[2] := EvalLIC2;
  CMV[3] := EvalLIC3;
  CMV[4] := EvalLIC4;
  CMV[5] := EvalLIC5;
  CMV[6] := EvalLIC6;
  CMV[7] := EvalLIC7;
  CMV[8] := EvalLIC8;
  CMV[9] := EvalLIC9;
  CMV[10] := EvalLIC10;
  CMV[11] := EvalLIC11;
  CMV[12] := EvalLIC12;
  CMV[13] := EvalLIC13;
  CMV[14] := EvalLIC14;
  CMV[15] := EvalLIC15;

  { Compute PUM off-diagonal elements }
  for i := 1 to 15 do
  begin
    for j := 1 to 15 do
    begin
      if i = j then Continue; { Diagonal is input }
      case LCM[i, j] of
        NOTUSED: PUM[i, j] := true;
        ANDD: PUM[i, j] := CMV[i] and CMV[j];
        ORR: PUM[i, j] := CMV[i] or CMV[j];
      end;
    end;
  end;

  { Compute FUV }
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
    begin
      FUV[i] := true;
    end
    else
    begin
      allTrue := true;
      for j := 1 to 15 do
      begin
        if not PUM[i, j] then
        begin
          allTrue := false;
          Break;
        end;
      end;
      FUV[i] := allTrue;
    end;
  end;

  { Compute LAUNCH }
  LAUNCH := true;
  for i := 1 to 15 do
  begin
    if not FUV[i] then
    begin
      LAUNCH := false;
      Break;
    end;
  end;
end;

procedure WriteOutput;
var
  i, j: integer;
begin
  Write('{"cmv":[');
  for i := 1 to 15 do
  begin
    if CMV[i] then Write('true') else Write('false');
    if i < 15 then Write(',');
  end;
  Write('],"pum":[');
  for i := 1 to 15 do
  begin
    Write('[');
    for j := 1 to 15 do
    begin
      if PUM[i, j] then Write('true') else Write('false');
      if j < 15 then Write(',');
    end;
    Write(']');
    if i < 15 then Write(',');
  end;
  Write('],"fuv":[');
  for i := 1 to 15 do
  begin
    if FUV[i] then Write('true') else Write('false');
    if i < 15 then Write(',');
  end;
  Write('],"launch":');
  if LAUNCH then Write('true') else Write('false');
  WriteLn('}');
end;

procedure ReadInput;
var
  line: string;
begin
  JsonStr := '';
  while not EOF do
  begin
    ReadLn(line);
    JsonStr := JsonStr + line;
  end;
  JsonPos := 1;
  ParseInput;
end;

begin
  ReadInput;
  DECIDE;
  WriteOutput;
end.
